 1	import type { FC } from 'react';
 2	import { ConsoleTimestamp } from 'src/components/ConsoleTimestamp/ConsoleTimestamp';
 3	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
 4	import { useForkliftTranslation } from 'src/utils/i18n';
 5	
 6	import { getCreatedAt } from '@utils/crds/common/selectors';
 7	import { MORE_INFO_CREATED_AT_DETAIL_ITEM } from '@utils/links';
 8	
 9	import type { ResourceDetailsItemProps } from './utils/types';
10	
11	const CreatedAtDetailsItem: FC<ResourceDetailsItemProps> = ({
12	  helpContent,
13	  moreInfoLink,
14	  resource,
15	}) => {
16	  const { t } = useForkliftTranslation();
17	
18	  const defaultHelpContent = t(
19	    `CreationTimestamp is a timestamp representing the server time when this object was created.
20	    It is not guaranteed to be set in happens-before order across separate operations.
21	    Clients may not set this value. It is represented in RFC3339 form and is in UTC.`,
22	  );
23	
24	  return (
25	    <DetailsItem
26	      testId="created-at-detail-item"
27	      title={t('Created at')}
28	      content={<ConsoleTimestamp timestamp={getCreatedAt(resource)} />}
29	      moreInfoLink={moreInfoLink ?? MORE_INFO_CREATED_AT_DETAIL_ITEM}
30	      helpContent={helpContent ?? defaultHelpContent}
31	      crumbs={['metadata', 'creationTimestamp']}
32	    />
33	  );
34	};
35	
36	export default CreatedAtDetailsItem;

